mapper.select:
/* 장치구분별 알람건수 조회 */ select count( case when device_type = '1' then 1 end ) as cnt_pcs, count( case when device_type = '2' then 1 end ) as cnt_bms, count( case when device_type = '3' then 1 end ) as cnt_pv, count( case when device_type = '4' then 1 end ) as cnt_ioe,
count( case when device_type not in ('1', '2', '3', '4') then 1 end ) as cnt_etc from ( select alarm_idx, site_id, device_id, device_type, std_date, alarm_type, alarm_msg, alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_note, reg_date, mod_date from tb_alarm where 1=1
and site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
) a

/* 알람 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				alarm_idx, site_id, device_id, device_type, std_date, alarm_type, alarm_msg, 
				alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_note, reg_date, mod_date
			from tb_alarm
			where 1=1
			
			and site_id = #{siteId }
			
			and device_type = #{alarmType }
			
			and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
limit #{startNum }, #{pageRowCnt }

/* 알람 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				alarm_idx, site_id, device_id, device_type, std_date, alarm_type, alarm_msg, 
				alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_note, reg_date, mod_date
			from tb_alarm
			where 1=1
			
			and site_id = #{siteId }
			
			and device_type = #{alarmType }
			
			and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
